CREATE TABLE `ai_tools` (
  `id` bigint NOT NULL COMMENT '主键ID',
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工具名称',
  `slug` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'URL友好标识',
  `official_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '官方网站URL',
  `logo_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Logo图片URL',
  `short_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '简短描述',
  `full_description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '完整描述',
  `category_id` bigint DEFAULT NULL COMMENT '主分类ID',
  `tags` json DEFAULT NULL COMMENT '标签列表',
  `use_cases` json DEFAULT NULL COMMENT '使用场景',
  `is_verified` tinyint(1) DEFAULT '0' COMMENT '是否已验证',
  `trust_score` float DEFAULT '0' COMMENT '信任评分(0-100)',
  `ssl_valid` tinyint(1) DEFAULT '0' COMMENT 'SSL证书是否有效',
  `domain_age_days` int DEFAULT NULL COMMENT '域名年龄(天)',
  `github_verified` tinyint(1) DEFAULT '0' COMMENT 'GitHub官方仓库验证',
  `github_repo_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'GitHub仓库URL',
  `github_stars` int DEFAULT NULL COMMENT 'GitHub星标数',
  `discovery_source` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '发现来源',
  `discovered_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '发现时间',
  `last_checked_at` datetime DEFAULT NULL COMMENT '最后检查时间',
  `last_updated_at` datetime DEFAULT NULL COMMENT '最后更新时间',
  `check_frequency_hours` int DEFAULT '24' COMMENT '检查频率(小时)',
  `pricing_model` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '定价模式(free/freemium/paid)',
  `pricing_details` json DEFAULT NULL COMMENT '定价详情',
  `api_available` tinyint(1) DEFAULT '0' COMMENT '是否提供API',
  `api_docs_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'API文档URL',
  `platform_support` json DEFAULT NULL COMMENT '平台支持',
  `view_count` int DEFAULT '0' COMMENT '浏览次数',
  `favorite_count` int DEFAULT '0' COMMENT '收藏次数',
  `click_count` int DEFAULT '0' COMMENT '点击次数',
  `popularity_score` float DEFAULT '0' COMMENT '热度评分',
  `is_sponsored` tinyint(1) DEFAULT '0' COMMENT '是否为赞助内容',
  `sponsor_level` int DEFAULT '0' COMMENT '赞助等级(0-无,1-5级)',
  `sponsor_start_date` datetime DEFAULT NULL COMMENT '赞助开始日期',
  `sponsor_end_date` datetime DEFAULT NULL COMMENT '赞助结束日期',
  `status` int DEFAULT '1' COMMENT '状态(0-禁用,1-启用,2-审核中)',
  `is_deleted` tinyint(1) DEFAULT '0' COMMENT '是否已删除',
  `metadata` json DEFAULT NULL COMMENT '扩展元数据',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='AI工具主表';

