INSERT INTO `nav_submission` (`id`, `url`, `submitter_name`, `contact_email`, `submitter_ip`, `ai_name`, `ai_slug`, `ai_description`, `ai_content`, `ai_pricing_type`, `ai_features`, `logo_url`, `screenshots`, `ai_category_id`, `ai_tag_ids`, `task_log`, `status`, `task_error`, `tool_id`, `admin_note`, `created_at`, `updated_at`) VALUES
(3, 'https://hao.aizhaozi.com', 'AI好参谋', 'ibaituo@sina.com', '27.158.11.47', 'AI好参谋', 'ai-hao-canmou', 'AI好参谋是一个聚合了海量AI工具的导航网站，旨在帮助用户快速发现和体验各类AI应用，涵盖写作、绘画、编程、视频等多个领域。', 'AI好参谋是一个功能全面的AI工具导航与发现平台。它通过精心分类和整理，将市面上主流的AI应用聚合在一处，为用户提供了一个便捷的“AI工具百宝箱”。产品特点在于其丰富的工具库、清晰的分类导航以及直观的用户界面，让无论是AI新手还是资深用户都能轻松找到所需工具。使用场景广泛，当用户需要完成特定AI任务（如生成文案、创作图片、编写代码）却不知从何入手时，可以通过该平台快速筛选和跳转到对应工具。目标用户包括内容创作者、设计师、开发者、营销人员以及对AI技术感兴趣的普通网民，是探索和高效利用AI资源的得力助手。', '免费', '[\"AI工具聚合导航\", \"多领域分类（写作/绘画/编程等）\", \"工具快速发现与推荐\", \"界面简洁易用\", \"定期更新工具库\"]', 'https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/3e34d85a113baa222b59d5ac2f29f21b656e7d954063af837ca3c283737ca951', '[\"https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/0d049b6e54e8487aca147304edc2680652d9ea0d669da9628854c82396b4dbd7\", \"https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/1448acb4ee85cc3774c1e1c1d07a4d869e770b3084327e19a2a68417b195efa8\", \"https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/01e58b77376db5e05f48e53b91ff8917a8a96ed10b12c2ec1b0dd7aea9674ed8\", \"https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/f6af404404bf34c004e8d6fb3cbb03bcf8af76084d3bec039ecfba1c93eb4141\"]', 7, '7,9,11', '[2026-04-04 21:30:37] 开始处理提交 #3，URL: https://hao.aizhaozi.com，名称: AI好参谋\n[2026-04-04 21:30:37] ── Step 1: 开始截图 ──\n[2026-04-04 21:30:37] 调用截图API: https://api.aihaocanmou.aizhaozi.com/api/v1/open/website-snapshot\n[2026-04-04 21:30:59] 截图完成: logo=有, 截图4张\n[2026-04-04 21:30:59]   Logo URL: https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/3e34d85a113baa222b59d5ac2f29f21b656e7d954063af837ca3c283737ca951\n[2026-04-04 21:30:59]   截图[1]: https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/0d049b6e54e8487aca147304edc2680652d9ea0d669da9628854c82396b4dbd7\n[2026-04-04 21:30:59]   截图[2]: https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/1448acb4ee85cc3774c1e1c1d07a4d869e770b3084327e19a2a68417b195efa8\n[2026-04-04 21:30:59]   截图[3]: https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/01e58b77376db5e05f48e53b91ff8917a8a96ed10b12c2ec1b0dd7aea9674ed8\n[2026-04-04 21:30:59]   截图[4]: https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/f6af404404bf34c004e8d6fb3cbb03bcf8af76084d3bec039ecfba1c93eb4141\n[2026-04-04 21:30:59] ── Step 2: 开始AI智能写作 ──\n[2026-04-04 21:30:59] 已加载 8 个分类、15 个标签供AI选择\n[2026-04-04 21:30:59] 调用AI接口: https://api.aihaocanmou.aizhaozi.com/api/v1/ai/chat (model=deepseek)\n[2026-04-04 21:31:06] AI写作完成，返回字段: [\'name\', \'slug\', \'description\', \'content\', \'pricing_type\', \'features\', \'category_id\', \'tag_ids\']\n[2026-04-04 21:31:06]   AI name: AI好参谋\n[2026-04-04 21:31:06]   AI slug: ai-hao-canmou\n[2026-04-04 21:31:06]   AI description: AI好参谋是一个聚合了海量AI工具的导航网站，旨在帮助用户快速发现和体验各类AI应用，涵盖写作、绘画、编程、视频等多个领...\n[2026-04-04 21:31:06]   AI pricing: 免费\n[2026-04-04 21:31:06]   AI features: [\'AI工具聚合导航\', \'多领域分类（写作/绘画/编程等）\', \'工具快速发现与推荐\', \'界面简洁易用\', \'定期更新工具库\']\n[2026-04-04 21:31:06]   AI category_id: 7\n[2026-04-04 21:31:06]   AI tag_ids: [7, 9, 11]\n[2026-04-04 21:31:06] ── Step 3: 保存结果 ──\n[2026-04-04 21:31:06] 自动分类: AI办公 (ID:7)\n[2026-04-04 21:31:06] 自动标签: 办公, 免费, 中文 (IDs:[7, 9, 11])\n[2026-04-04 21:31:06] 处理完成，状态变为 ready', 'approved', NULL, 8, NULL, '2026-04-04 21:30:37', '2026-04-04 21:32:09'),
(13, 'https://stepwise.ai?ref=hao.aizhaozi.com', 'Stepwise AI', NULL, 'system:daily-tools', 'Stepwise AI', 'stepwise-ai', '国产AI编程助手，专注代码解释、调试与工程级重构建议。', '<div>\n  <!-- 产品介绍 -->\n  <p class=\"mt-3\">\n    Stepwise AI 是一个提供 AI 战略咨询与落地实施服务的专业团队。\n  </p>\n  <p class=\"mt-3\">\n    如果你正在考虑怎么把 AI 真正用到业务里，或者已经尝试但卡在架构、部署或团队能力上，Stepwise AI 能帮你从规划到上线一步步走通。他们特别适合那些需要在医疗、金融等强监管行业落地 AI 的团队，也支持做定制培训，让你的团队不仅能用 AI，还能持续迭代。\n  </p>\n\n  <!-- 主要功能 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    主要功能\n  </h2>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">功能</th>\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">说明</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 战略咨询</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">帮你制定贴合业务目标的 AI 路线图，包括技术选型、实施计划和 ROI 分析</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 实施支持</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">提供架构设计、技术指导和最佳实践，协助团队实际构建和部署 AI 系统</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 培训与工作坊</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">为团队定制实操型培训，内容涵盖 LLM 集成、RAG 系统等，并提供持续支持</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- 定价方案 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    定价方案\n  </h2>\n  <p class=\"mt-2 text-gray-600 text-sm\">定价根据具体服务内容定制，需联系团队获取详细费用信息。</p>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">方案</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">价格</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">包含内容</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">咨询服务</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-center text-gray-700\">查看官网</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">AI 战略、实施或培训服务，按项目或小时计费</td>\n      </tr>\n    </tbody>\n  </table>\n  <p class=\"text-center mt-4\">\n    <a\n      href=\"https://stepwise.ai?ref=hao.aizhaozi.com\"\n      target=\"_blank\"\n      rel=\"noopener\"\n      class=\"inline-block px-5 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition text-sm\">\n      访问官网了解详情\n    </a>\n  </p>\n\n  <!-- 使用建议 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    使用建议\n  </h2>\n  <div class=\"mt-3 text-gray-700 text-sm space-y-2\">\n    <p>适合已经有明确 AI 应用场景、但缺乏落地经验的技术团队或管理者，尤其是身处医疗、金融等受监管行业的企业。</p>\n    <p>也适合希望系统提升团队 AI 实战能力、而不仅是听理论讲座的组织。</p>\n    <p>具体使用体验和详细功能，建议访问官网了解。</p>\n  </div>\n</div>', '免费', '[\"代码解释\", \"代码调试\", \"工程级重构建议\", \"编程辅助\", \"国产AI工具\"]', 'https://www.hao.aizhaozi.com/api/admin/media/preview/098b85f5086c378531d45033c1fe5e1bd129a0db18f0481bdde260f62df410f5', '[\"https://www.hao.aizhaozi.com/api/admin/media/preview/098b85f5086c378531d45033c1fe5e1bd129a0db18f0481bdde260f62df410f5\", \"https://www.hao.aizhaozi.com/api/admin/media/preview/268b8d078e51d79d74a9389a045a7a5f0a2aeb3be8f2c6ce1b04295704a75096\", \"https://www.hao.aizhaozi.com/api/admin/media/preview/d2870492fa7f49b45b8597a37ee8f71f5cba147a3ace868ceb74a321f5db721a\", \"https://www.hao.aizhaozi.com/api/admin/media/preview/26d701cb02f68ee1dfac9d616b246dd0f36717d52ad947c98177b1cd5691a0e0\"]', 10, '4,16,17,18,19', '[2026-04-04 23:29:37] 来源: 每日AI工具采集 (2026-04-03)\n[2026-04-04 23:29:37] 原始平台工具ID: 445\n[2026-04-04 23:29:37] Logo: https://www.hao.aizhaozi.com/api/admin/media/preview/f8b6f2ced0f5f14b9a7dc9db0bd1ca41082f91ebfa4c811e42f7252564a6cbd3\n[2026-04-04 23:29:37] 截图: 4 张\n[2026-04-04 23:29:37] 封面图: https://www.hao.aizhaozi.com/api/admin/media/preview/098b85f5086c378531d45033c1fe5e1bd129a0db18f0481bdde260f62df410f5\n[2026-04-04 23:29:37] 分类: 精确匹配 \'代码助手\'\n[2026-04-04 23:29:37] 标签: 编程辅助(match:4), 国产AI(match:16), 代码解释(match:17), 代码调试(match:18), 代码重构(match:19)\n[2026-04-04 23:29:37] ── 开始AI补全功能特性 ──\n[2026-04-04 23:29:39] AI补全功能特性: [\'代码解释\', \'代码调试\', \'工程级重构建议\', \'编程辅助\', \'国产AI工具\']', 'approved', NULL, 10, NULL, '2026-04-04 23:29:40', '2026-04-04 23:30:12'),
(14, 'https://www.blinkist.com/?ref=hao.aizhaozi.com', 'Blinkist AI', NULL, 'system:daily-tools', 'Blinkist AI', 'blinkist-ai', '将书籍/文章提炼为AI语音摘要，2024新增个性化学习路径与问答模式。', '<div>\n  <!-- 产品介绍 -->\n  <p class=\"mt-3\">\n    Blinkist AI 是一个帮你快速获取知识精华的工具，能把书、播客、文章、视频等内容浓缩成15分钟能读完或听完的摘要。\n  </p>\n  <p class=\"mt-3\">\n    如果你没时间读完整本书，或者想高效了解多个领域的核心观点，Blinkist 能帮你从9000多个精选书和播客中提取关键内容，还能根据你的兴趣推荐每日学习内容，适合通勤、休息或碎片时间使用。\n  </p>\n\n  <!-- 主要功能 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    主要功能\n  </h2>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">功能</th>\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">说明</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 内容摘要</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">能总结视频、播客、文档、文章等多种内容，提炼核心观点。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">书与播客精华库</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">提供9000+本畅销书和热门播客的15分钟摘要，覆盖多个主题领域。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">个性化每日推荐</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">根据你的兴趣和学习历史，每天推送适合你的内容。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">多格式学习支持</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">支持阅读文本摘要或收听音频版本，适应不同学习习惯。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">学习内容整合</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">可以保存并连接你在不同地方学到的知识点，形成个人知识库。</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- 定价方案 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    定价方案\n  </h2>\n  <p class=\"mt-2 text-gray-600 text-sm\">Blinkist 提供 PRO 付费方案，按月或按年订阅，包含全部 AI 功能和内容库访问权限。</p>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">方案</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">价格</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">包含内容</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">PRO（1个月）</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-center text-gray-700\">查看官网</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">Blinkist AI 摘要功能、9000+书和播客摘要、15分钟阅读/收听、每日个性化推荐</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">PRO（12个月）</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-center text-gray-700\">查看官网</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">Blinkist AI 摘要功能、9000+书和播客摘要、15分钟阅读/收听、每日个性化推荐</td>\n      </tr>\n    </tbody>\n  </table>\n  <p class=\"text-center mt-4\">\n    <a\n      href=\"https://www.blinkist.com/?ref=hao.aizhaozi.com\"\n      target=\"_blank\"\n      rel=\"noopener\"\n      class=\"inline-block px-5 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition text-sm\">\n      访问官网了解详情\n    </a>\n  </p>\n\n  <!-- 使用建议 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    使用建议\n  </h2>\n  <div class=\"mt-3 text-gray-700 text-sm space-y-2\">\n    <p>适合想高效学习但时间有限的人，比如上班族、学生或终身学习者。</p>\n    <p>如果你经常听播客、看文章或读书，但希望快速抓住重点，Blinkist 的 AI 摘要和精华库会很有帮助。</p>\n    <p>具体使用体验和详细功能，建议访问官网了解。</p>\n  </div>\n</div>', '免费', '[\"书籍文章AI语音摘要\", \"个性化学习路径推荐\", \"智能问答模式\", \"核心内容提炼\", \"音频形式知识获取\"]', 'https://www.hao.aizhaozi.com/api/admin/media/preview/c262c3d5d046a448c7f0fcfb364d387ecdf4513d9479b5f2a9b9007a0ad16d74', '[\"https://www.hao.aizhaozi.com/api/admin/media/preview/c262c3d5d046a448c7f0fcfb364d387ecdf4513d9479b5f2a9b9007a0ad16d74\", \"https://www.hao.aizhaozi.com/api/admin/media/preview/749ba2b750226f8c648b08aad43902cb3fbec9ac905b8c07f84fc94267d2a01a\", \"https://www.hao.aizhaozi.com/api/admin/media/preview/d42eaf44737a59c72adf8f1cc11e154d2fd245a5c62dc2d486b25c282a27bb6e\", \"https://www.hao.aizhaozi.com/api/admin/media/preview/3e8b9fa165901f1d3f1186f23ac7d7830f8a6a104779167a5b0144834a4842b4\"]', 11, '20,21,22,23', '[2026-04-04 23:29:39] 来源: 每日AI工具采集 (2026-04-03)\n[2026-04-04 23:29:39] 原始平台工具ID: 432\n[2026-04-04 23:29:39] Logo: https://www.hao.aizhaozi.com/api/admin/media/preview/37c756ed256b6b27aca7ecce1f0dd1b9ae28777204d3cb0ddf4eb3e45aff9d04\n[2026-04-04 23:29:39] 截图: 4 张\n[2026-04-04 23:29:39] 封面图: https://www.hao.aizhaozi.com/api/admin/media/preview/c262c3d5d046a448c7f0fcfb364d387ecdf4513d9479b5f2a9b9007a0ad16d74\n[2026-04-04 23:29:39] 分类: 精确匹配 \'Ai大模型\'\n[2026-04-04 23:29:39] 标签: 内容提炼(match:20), 语音摘要(match:21), 个性化学习(match:22), 问答交互(match:23)\n[2026-04-04 23:29:39] ── 开始AI补全功能特性 ──\n[2026-04-04 23:29:41] AI补全功能特性: [\'书籍文章AI语音摘要\', \'个性化学习路径推荐\', \'智能问答模式\', \'核心内容提炼\', \'音频形式知识获取\']', 'approved', NULL, 9, NULL, '2026-04-04 23:29:41', '2026-04-04 23:30:08');
