INSERT INTO `nav_tool` (`id`, `name`, `slug`, `description`, `content`, `icon`, `cover`, `url`, `category_id`, `pricing_type`, `pricing_desc`, `features`, `views`, `clicks`, `likes`, `hot`, `seo_title`, `seo_desc`, `is_recommended`, `status`, `sort`, `created_at`, `updated_at`) VALUES
(1, 'ChatGPT', 'chatgpt', 'OpenAI开发的强大AI对话助手，支持多种任务处理', 'ChatGPT是由OpenAI开发的大型语言模型，能够进行自然语言对话、回答问题、协助写作、编程、分析等多种任务。它基于GPT架构，通过大量文本数据训练，具有强大的语言理解和生成能力。', 'https://ai-dh.sslphp.com/api/admin/media/preview/44a9da28841d50cb5689ef79ef8309ac7baa49e2f2abff5f034affe9d3645ebe', 'https://ai-dh.sslphp.com/api/admin/media/preview/063682537edfe58dea4e91cf0a4940a4cd67f6c3a537216e3f11c60d8e455fba', 'https://chat.openai.com', 3, 'freemium', '免费版可用，Plus订阅$20/月', '[\"\\u81ea\\u7136\\u8bed\\u8a00\\u5bf9\\u8bdd\", \"\\u4ee3\\u7801\\u7f16\\u5199\\u4e0e\\u8c03\\u8bd5\", \"\\u6587\\u672c\\u521b\\u4f5c\", \"\\u6570\\u636e\\u5206\\u6790\", \"\\u591a\\u8bed\\u8a00\\u652f\\u6301\"]', 125053, 1, 0, 99, NULL, NULL, 1, 1, 1, '2026-04-04 08:39:17', '2026-04-05 21:28:46'),
(2, 'Midjourney', 'midjourney', '顶级AI绘画工具，生成高质量艺术图像', 'Midjourney是一款领先的AI图像生成工具，通过文本描述即可创建精美的艺术图像。它以其独特的艺术风格和高质量的输出而闻名，广泛应用于设计、艺术创作等领域。', 'https://via.placeholder.com/128', 'https://via.placeholder.com/800x400', 'https://midjourney.com', 2, 'paid', '订阅制，基础版$10/月起', '[\"\\u6587\\u672c\\u751f\\u6210\\u56fe\\u50cf\", \"\\u827a\\u672f\\u98ce\\u683c\\u591a\\u6837\", \"\\u9ad8\\u6e05\\u8f93\\u51fa\", \"Discord\\u96c6\\u6210\", \"\\u793e\\u533a\\u5206\\u4eab\"]', 98031, 0, 0, 95, NULL, NULL, 1, 1, 2, '2026-04-04 08:39:17', '2026-04-05 14:00:35'),
(3, 'Claude', 'claude', 'Anthropic推出的AI助手，擅长长文本处理', 'Claude是由Anthropic开发的AI助手，以其强大的推理能力和长文本处理能力著称。它能够处理大量上下文，适合文档分析、代码审查等复杂任务。', 'https://via.placeholder.com/128', NULL, 'https://claude.ai', 3, 'freemium', '免费版可用，Pro$20/月', '[\"\\u957f\\u6587\\u672c\\u5904\\u7406\", \"\\u4ee3\\u7801\\u5206\\u6790\", \"\\u6587\\u6863\\u7406\\u89e3\", \"\\u5b89\\u5168\\u53ef\\u63a7\", \"\\u591a\\u8f6e\\u5bf9\\u8bdd\"]', 76003, 0, 0, 88, NULL, NULL, 0, 1, 3, '2026-04-04 08:39:17', '2026-04-04 13:46:56'),
(4, 'GitHub Copilot', 'github-copilot', 'AI编程助手，提升开发效率的必备工具', 'GitHub Copilot是由GitHub和OpenAI合作开发的AI编程助手，能够根据注释和代码上下文自动生成代码建议。它支持多种编程语言，深度集成主流IDE。', 'https://via.placeholder.com/128', 'https://via.placeholder.com/800x400', 'https://github.com/copilot', 4, 'paid', '个人版$10/月，企业版$19/月', '[\"\\u4ee3\\u7801\\u81ea\\u52a8\\u8865\\u5168\", \"\\u6ce8\\u91ca\\u751f\\u6210\\u4ee3\\u7801\", \"\\u591a\\u8bed\\u8a00\\u652f\\u6301\", \"IDE\\u96c6\\u6210\", \"\\u4ee3\\u7801\\u89e3\\u91ca\"]', 112005, 0, 0, 92, NULL, NULL, 1, 1, 4, '2026-04-04 08:39:17', '2026-04-05 10:54:50'),
(5, 'Notion AI', 'notion-ai', '集成在Notion中的AI写作助手', 'Notion AI是集成在Notion工作空间中的AI助手，能够帮助用户快速生成内容、总结文档、改进写作等。它与Notion的协作功能深度结合，提升团队效率。', 'https://via.placeholder.com/128', NULL, 'https://notion.so', 7, 'paid', '按使用量计费', '[\"文档生成\", \"内容总结\", \"写作改进\", \"头脑风暴\", \"多语言翻译\"]', 54005, 0, 0, 78, NULL, NULL, 0, 1, 5, '2026-04-04 08:39:17', '2026-04-04 14:15:14'),
(6, 'Runway', 'runway', 'AI视频编辑和生成平台', 'Runway是一款强大的AI视频编辑和生成工具，提供视频抠像、风格转换、文本生成视频等功能。它结合了传统视频编辑和AI技术，适合创作者使用。', 'https://via.placeholder.com/128', 'https://via.placeholder.com/800x400', 'https://runwayml.com', 5, 'freemium', '免费版可用，标准版$15/月', '[\"\\u89c6\\u9891\\u62a0\\u50cf\", \"\\u98ce\\u683c\\u8f6c\\u6362\", \"\\u6587\\u672c\\u751f\\u6210\\u89c6\\u9891\", \"\\u8fd0\\u52a8\\u8ffd\\u8e2a\", \"\\u534f\\u4f5c\\u7f16\\u8f91\"]', 43000, 0, 0, 82, NULL, NULL, 0, 1, 6, '2026-04-04 08:39:17', '2026-04-04 13:24:36'),
(8, 'AI好参谋', 'ai-hao-canmou', 'AI好参谋是一个聚合了海量AI工具的导航网站，旨在帮助用户快速发现和体验各类AI应用，涵盖写作、绘画、编程、视频等多个领域。', 'AI好参谋是一个功能全面的AI工具导航与发现平台。它通过精心分类和整理，将市面上主流的AI应用聚合在一处，为用户提供了一个便捷的“AI工具百宝箱”。产品特点在于其丰富的工具库、清晰的分类导航以及直观的用户界面，让无论是AI新手还是资深用户都能轻松找到所需工具。使用场景广泛，当用户需要完成特定AI任务（如生成文案、创作图片、编写代码）却不知从何入手时，可以通过该平台快速筛选和跳转到对应工具。目标用户包括内容创作者、设计师、开发者、营销人员以及对AI技术感兴趣的普通网民，是探索和高效利用AI资源的得力助手。', 'https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/3e34d85a113baa222b59d5ac2f29f21b656e7d954063af837ca3c283737ca951', 'https://api.aihaocanmou.aizhaozi.com/api/admin/media/preview/0d049b6e54e8487aca147304edc2680652d9ea0d669da9628854c82396b4dbd7', 'https://hao.aizhaozi.com', 7, '免费', NULL, '[\"AI\\u5de5\\u5177\\u805a\\u5408\\u5bfc\\u822a\", \"\\u591a\\u9886\\u57df\\u5206\\u7c7b\\uff08\\u5199\\u4f5c/\\u7ed8\\u753b/\\u7f16\\u7a0b\\u7b49\\uff09\", \"\\u5de5\\u5177\\u5feb\\u901f\\u53d1\\u73b0\\u4e0e\\u63a8\\u8350\", \"\\u754c\\u9762\\u7b80\\u6d01\\u6613\\u7528\", \"\\u5b9a\\u671f\\u66f4\\u65b0\\u5de5\\u5177\\u5e93\"]', 960018, 1, 0, 1, NULL, NULL, 1, 1, 10, '2026-04-04 21:32:09', '2026-04-05 16:28:45'),
(9, 'Blinkist AI', 'blinkist-ai', '将书籍/文章提炼为AI语音摘要，2024新增个性化学习路径与问答模式。', '<div>\n  <!-- 产品介绍 -->\n  <p class=\"mt-3\">\n    Blinkist AI 是一个帮你快速获取知识精华的工具，能把书、播客、文章、视频等内容浓缩成15分钟能读完或听完的摘要。\n  </p>\n  <p class=\"mt-3\">\n    如果你没时间读完整本书，或者想高效了解多个领域的核心观点，Blinkist 能帮你从9000多个精选书和播客中提取关键内容，还能根据你的兴趣推荐每日学习内容，适合通勤、休息或碎片时间使用。\n  </p>\n\n  <!-- 主要功能 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    主要功能\n  </h2>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">功能</th>\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">说明</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 内容摘要</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">能总结视频、播客、文档、文章等多种内容，提炼核心观点。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">书与播客精华库</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">提供9000+本畅销书和热门播客的15分钟摘要，覆盖多个主题领域。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">个性化每日推荐</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">根据你的兴趣和学习历史，每天推送适合你的内容。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">多格式学习支持</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">支持阅读文本摘要或收听音频版本，适应不同学习习惯。</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">学习内容整合</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">可以保存并连接你在不同地方学到的知识点，形成个人知识库。</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- 定价方案 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    定价方案\n  </h2>\n  <p class=\"mt-2 text-gray-600 text-sm\">Blinkist 提供 PRO 付费方案，按月或按年订阅，包含全部 AI 功能和内容库访问权限。</p>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">方案</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">价格</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">包含内容</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">PRO（1个月）</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-center text-gray-700\">查看官网</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">Blinkist AI 摘要功能、9000+书和播客摘要、15分钟阅读/收听、每日个性化推荐</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">PRO（12个月）</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-center text-gray-700\">查看官网</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">Blinkist AI 摘要功能、9000+书和播客摘要、15分钟阅读/收听、每日个性化推荐</td>\n      </tr>\n    </tbody>\n  </table>\n  <p class=\"text-center mt-4\">\n    <a\n      href=\"https://www.blinkist.com/?ref=hao.aizhaozi.com\"\n      target=\"_blank\"\n      rel=\"noopener\"\n      class=\"inline-block px-5 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition text-sm\">\n      访问官网了解详情\n    </a>\n  </p>\n\n  <!-- 使用建议 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    使用建议\n  </h2>\n  <div class=\"mt-3 text-gray-700 text-sm space-y-2\">\n    <p>适合想高效学习但时间有限的人，比如上班族、学生或终身学习者。</p>\n    <p>如果你经常听播客、看文章或读书，但希望快速抓住重点，Blinkist 的 AI 摘要和精华库会很有帮助。</p>\n    <p>具体使用体验和详细功能，建议访问官网了解。</p>\n  </div>\n</div>', 'https://www.hao.aizhaozi.com/api/admin/media/preview/c262c3d5d046a448c7f0fcfb364d387ecdf4513d9479b5f2a9b9007a0ad16d74', 'https://www.hao.aizhaozi.com/api/admin/media/preview/c262c3d5d046a448c7f0fcfb364d387ecdf4513d9479b5f2a9b9007a0ad16d74', 'https://www.blinkist.com/?ref=hao.aizhaozi.com', 11, '免费', NULL, '[\"书籍文章AI语音摘要\", \"个性化学习路径推荐\", \"智能问答模式\", \"核心内容提炼\", \"音频形式知识获取\"]', 4, 1, 0, 1, NULL, NULL, 0, 1, 0, '2026-04-04 23:30:08', '2026-04-05 16:25:00'),
(10, 'Stepwise AI', 'stepwise-ai', '国产AI编程助手，专注代码解释、调试与工程级重构建议。', '<div>\n  <!-- 产品介绍 -->\n  <p class=\"mt-3\">\n    Stepwise AI 是一个提供 AI 战略咨询与落地实施服务的专业团队。\n  </p>\n  <p class=\"mt-3\">\n    如果你正在考虑怎么把 AI 真正用到业务里，或者已经尝试但卡在架构、部署或团队能力上，Stepwise AI 能帮你从规划到上线一步步走通。他们特别适合那些需要在医疗、金融等强监管行业落地 AI 的团队，也支持做定制培训，让你的团队不仅能用 AI，还能持续迭代。\n  </p>\n\n  <!-- 主要功能 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    主要功能\n  </h2>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">功能</th>\n        <th class=\"border border-gray-200 px-3 py-2 text-left font-medium text-gray-900\">说明</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 战略咨询</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">帮你制定贴合业务目标的 AI 路线图，包括技术选型、实施计划和 ROI 分析</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 实施支持</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">提供架构设计、技术指导和最佳实践，协助团队实际构建和部署 AI 系统</td>\n      </tr>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">AI 培训与工作坊</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">为团队定制实操型培训，内容涵盖 LLM 集成、RAG 系统等，并提供持续支持</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <!-- 定价方案 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    定价方案\n  </h2>\n  <p class=\"mt-2 text-gray-600 text-sm\">定价根据具体服务内容定制，需联系团队获取详细费用信息。</p>\n  <table class=\"w-full border-collapse border border-gray-200 mt-3 text-sm\">\n    <thead>\n      <tr class=\"bg-gray-50\">\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">方案</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">价格</th>\n        <th class=\"border border-gray-200 px-3 py-2 font-medium text-gray-900\">包含内容</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td class=\"border border-gray-200 px-3 py-2 font-medium text-gray-800\">咨询服务</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-center text-gray-700\">查看官网</td>\n        <td class=\"border border-gray-200 px-3 py-2 text-gray-700\">AI 战略、实施或培训服务，按项目或小时计费</td>\n      </tr>\n    </tbody>\n  </table>\n  <p class=\"text-center mt-4\">\n    <a\n      href=\"https://stepwise.ai?ref=hao.aizhaozi.com\"\n      target=\"_blank\"\n      rel=\"noopener\"\n      class=\"inline-block px-5 py-2 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 transition text-sm\">\n      访问官网了解详情\n    </a>\n  </p>\n\n  <!-- 使用建议 -->\n  <h2 class=\"text-xl font-bold text-gray-800 mt-6\">\n    使用建议\n  </h2>\n  <div class=\"mt-3 text-gray-700 text-sm space-y-2\">\n    <p>适合已经有明确 AI 应用场景、但缺乏落地经验的技术团队或管理者，尤其是身处医疗、金融等受监管行业的企业。</p>\n    <p>也适合希望系统提升团队 AI 实战能力、而不仅是听理论讲座的组织。</p>\n    <p>具体使用体验和详细功能，建议访问官网了解。</p>\n  </div>\n</div>', 'https://www.hao.aizhaozi.com/api/admin/media/preview/098b85f5086c378531d45033c1fe5e1bd129a0db18f0481bdde260f62df410f5', 'https://www.hao.aizhaozi.com/api/admin/media/preview/098b85f5086c378531d45033c1fe5e1bd129a0db18f0481bdde260f62df410f5', 'https://stepwise.ai?ref=hao.aizhaozi.com', 10, '免费', NULL, '[\"代码解释\", \"代码调试\", \"工程级重构建议\", \"编程辅助\", \"国产AI工具\"]', 0, 0, 0, 0, NULL, NULL, 0, 1, 0, '2026-04-04 23:30:12', '2026-04-04 23:30:12');
